 * Enfile 2 messages avec priorites, defile dans l'ordre FIFO.
 * ========================================================= */
MsgBuf example_q[QUEUE_LEN];
int example_head = 0, example_tail = 0;

void example_enqueue(long prio, const char *text) {
    example_q[example_tail].mtype = prio;
    strncpy(example_q[example_tail].mtext, text, MSG_SIZE - 1);
    example_tail++;
}

int example_dequeue(MsgBuf *out) {
    if (example_head >= example_tail) return -1;
    *out = example_q[example_head++];
    return 0;
}

void example_priority_queue(void) {
    example_enqueue(3, "low priority");
    example_enqueue(1, "high priority");
    MsgBuf m;
    while (example_dequeue(&m) == 0)
